sql:
SELECT component_name, status
FROM software_components
ORDER BY component_id ASC;

SELECT component_id
FROM software_components
WHERE component_name = 'SIG Action';

SELECT component_name
FROM software_components
WHERE created_at = (SELECT MIN(created_at) FROM software_components);

external_knowledge:
- 'Describe the length of time it took to run them' refers to categorizing the average test duration into 'long', 'medium', or 'short' based on the thresholds of 1000 and 500; 
- 'Default Configuration' refers to the configuration name 'Default Configuration' in the test_configurations table; 
- 'May 2023' refers to the month of May in the year 2023, bounded by the dates '2023-05-01 00:00:00' and '2023-05-31 23:59:59'.

sql:
SELECT component_name
FROM software_components
WHERE component_id NOT IN (
  SELECT component_id
  FROM test_cases
);

SELECT DISTINCT test_case_name
FROM test_cases
WHERE testable = 0 AND test_case_id = 1;

SELECT COUNT(test_suite_id)
  FROM test_case_test_suites
  WHERE test_case_id = 1;

SELECT COUNT(*) 
FROM test_cases 
WHERE component_id = 0 AND test_case_name = 'hasGetUserPrincipalReturns';

SELECT test_case_id, test_suite_id
FROM test_results
WHERE test_result_id = (SELECT MIN(test_result_id) FROM test_results);
